62	/**@ch 懸賞令管理器*/
63	@ccclass('WantedPosterManager')
64	export class WantedPosterManager extends Component {
65	    //#region Constants
66	    /**
67	     * @ch 需要註冊的事件列表
68	     */
69	    private static readonly EVENTS_TO_REGISTER = [
70	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA,
71	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW,
72	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
73	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
74	        WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE,
75	        GAME_EVENT.DEVICE_ROTATION,
76	    ];
77	    //#endregion Constants
78	
79	    //#region Properties
80	    @property({
81	        type: Node,
82	        tooltip: "根節點"
83	    })
84	    private m_rootNode: Node = null;
85	
86	    @property({
87	        type: [WantedPosterItem],
88	        tooltip: "懸賞令物品"
89	    })
90	    private m_wantedPosterItems: WantedPosterItem[] = [];
91	
92	    @property({
93	        type: Layout,
94	        tooltip: "懸賞令排版元件（m_wantedPosterItems 父節點上的 cc.Layout）"
95	    })
96	    private m_layout: Layout = null;
97	
98	    @property({
99	        type: WantedPosterLayoutConfig,
100	        tooltip: "直向排版設定"
101	    })
102	    private m_portraitConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
103	
104	    @property({
105	        type: WantedPosterLayoutConfig,
106	        tooltip: "橫向排版設定"
107	    })
108	    private m_landscapeConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
109	    //#endregion Properties
110	
111	    //#region Variables
112	    /**@ch 是否已初始化*/
113	    private m_isInitialized: boolean = false;
114	
115	    /**
116	     * @ch 各 item 目前綁定的懸賞令資料（null = 該 item 未顯示）
117	     * 與 m_wantedPosterItems 同索引，是「同 BaseSymbol 持續判斷」與「倍率是否變」的真實依據
118	     * （item 本身只記 BaseSymbol、不記 Multiple，故由 Manager 統一追蹤）
119	     */
120	    private m_currentBounty: (IBountyData | null)[] = [];
121	    //#endregion Variables
122	
123	    //#region Lifecycle
124	    /**@ch 元件載入時調用*/
125	    onLoad() {
126	        this.RegisterEvent();
127	        this.RegisterKeyboardEvents();
128	        this.EnsureCurrentBountySize();
129	    }
130	
131	    /**@ch 元件啟動時調用（GameView 已就緒，套用初始方向 Layout）*/
132	    start() {
133	        this.ApplyLayoutByOrientation();
134	    }
135	
136	    /**@ch 元件銷毀時調用*/
137	    onDestroy() {
138	        if (!this.m_isInitialized) return;
139	        this.UnregisterEvent();
140	        this.UnregisterKeyboardEvents();
141	        this.m_isInitialized = false;
142	    }
143	    //#endregion Lifecycle
144	
145	    //#region Event Management
146	    /**@ch 註冊鍵盤事件（測試用）*/
147	    private RegisterKeyboardEvents(): void {
148	        if (!DEBUG) return;
149	        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
150	    }
151	
152	    /**@ch 取消註冊鍵盤事件（測試用）*/
153	    private UnregisterKeyboardEvents(): void {
154	        if (!DEBUG) return;
155	        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
156	    }
157	
158	    /**@ch 註冊事件*/
159	    private RegisterEvent() {
160	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
161	            eventManager.Register(eventName, this);
162	        });
163	        this.m_isInitialized = true;
164	    }
165	
166	    /**@ch 取消註冊事件*/
167	    private UnregisterEvent() {
168	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
169	            eventManager.UnRegister(eventName, this);
170	        });
171	    }
172	
173	    /**
174	     * @ch 驗證 SET_WANTED_POSTER_UI_SHOW 事件參數
175	     * @param args 事件參數
176	     * @returns 是否有效
177	     */
178	    private ValidateSetWantedPosterUIShowArgs(args: any[]): boolean {
179	        if (typeof args[0] !== 'boolean') {
180	            warn('[WantedPosterManager] SET_WANTED_POSTER_UI_SHOW: 無效的參數', args[0]);
181	            return false;
182	        }
183	        return true;
184	    }
185	
186	    /**
187	     * @ch 驗證 SET_WANTED_POSTER_DATA 事件參數
188	     * @param args 事件參數
189	     * @returns 是否有效
190	     */
191	    private ValidateSetWantedPosterDataArgs(args: any[]): boolean {
192	        if (!Array.isArray(args[0])) {
193	            warn('[WantedPosterManager] SET_WANTED_POSTER_DATA: 無效的資料參數', args[0]);
194	            return false;
195	        }
196	        return true;
197	    }
198	
199	    /**
200	     * @ch 事件回調
201	     * @param event 事件名稱
202	     * @param args 事件參數
203	     */
204	    OnEvent(event: string, ...args: any[]) {
205	        switch (event) {
206	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA:
207	                if (this.ValidateSetWantedPosterDataArgs(args)) {
208	                    this.SetWantedPosterData(
209	                        args[0] as IBountyData[],
210	                        args[1] === true,
211	                        Array.isArray(args[2]) ? args[2] as number[] : undefined
212	                    );
213	                }
214	                break;
215	
216	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW:
217	                if (this.ValidateSetWantedPosterUIShowArgs(args)) {
218	                    this.SetWantedPosterUIShow(args[0] as boolean);
219	                }
220	                break;
221	
222	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
223	                this.HandlePlayMark(args[0] as number, args[1] as () => void);
224	                break;
225	
226	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
227	                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
228	                break;
229	
230	            case WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE:
231	                this.HandleGameIntroComplete();
232	                break;
233	
234	            case GAME_EVENT.DEVICE_ROTATION:
235	                this.ApplyLayoutByOrientation();
236	                break;
237	
238	            default:
239	                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
240	        }
241	    }
242	
243	    /**
244	     * @ch 依目前裝置方向套用對應的 Layout 設定
245	     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
246	     */
247	    private ApplyLayoutByOrientation(): void {
248	        if (!this.m_layout) {
249	            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
250	            return;
251	        }
252	        const isLandscape = Common.GetGameView().IsLandscape;
253	        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;
254	
255	        this.m_layout.type = cfg.type;
256	        this.m_layout.resizeMode = cfg.resizeMode;
257	        this.m_layout.paddingLeft = cfg.paddingLeft;
258	        this.m_layout.paddingRight = cfg.paddingRight;
259	        this.m_layout.paddingTop = cfg.paddingTop;
260	        this.m_layout.paddingBottom = cfg.paddingBottom;
261	        this.m_layout.spacingX = cfg.spacingX;
262	        this.m_layout.spacingY = cfg.spacingY;
263	        this.m_layout.alignHorizontal = cfg.alignHorizontal;
264	        this.m_layout.alignVertical = cfg.alignVertical;
265	        this.m_layout.updateLayout();
266	    }
267	
268	    /**
269	     * @ch 處理 PLAY_MARK 事件
270	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
271	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
272	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
273	     * EH-9：resolve callback 缺失 → error（caller bug）
274	     */
275	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
276	        if (typeof resolve !== 'function') {
277	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
278	            return;
279	        }
280	        const items = this.GetItemsByBaseSymbol(baseSymbol);
281	        if (items.length === 0) {
282	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
283	            resolve();
284	            return;
285	        }
286	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
287	    }
288	
289	    /**
290	     * @ch 處理 PLAY_MARK_ACTIVE 事件
291	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
292	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
293	     * EH-9：resolve callback 缺失 → error
294	     */
295	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
296	        if (typeof resolve !== 'function') {
297	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
298	            return;
299	        }
300	        const items = this.GetItemsByBaseSymbol(baseSymbol);
301	        if (items.length === 0) {
302	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
303	            resolve();
304	            return;
305	        }
306	        // ── 同步段（Promise.all 之前）：先清本批綁定。並行的其他 dispatch（WantedPosterState 跨 group）
307	        //    也各自同步清，故動畫完成時的 ghost 判定能看到「本波所有離場者皆已退」（§5.5 race 修正）
308	        for (const item of items) {
309	            const idx = this.m_wantedPosterItems.indexOf(item);
310	            if (idx >= 0) this.m_currentBounty[idx] = null;
311	            item.ClearBaseSymbol();
312	        }
313	        // ── 非同步段：動畫播完才切換視覺。判定移到 .then（此時全波同步段已執行完）：
314	        //    仍有 real（survivor 留場）→ 轉 ghost 撐位讓 survivor 不 snap；否則真消失（BC-G6）
315	        Promise.all(items.map(item =>
316	            item.PlayMarkActive().then(() => {
317	                if (this.m_currentBounty.some(b => b !== null)) item.SetContentVisible(false);
318	                else item.node.active = false;
319	            })
320	        )).then(() => {
321	            // 本波後若全場無 real → 釋放殘留 ghost（避免上一輪保留的 ghost 隱形殘留 · §5.3.1）
322	            if (!this.m_currentBounty.some(b => b !== null)) this.NormalizeGhosts();
323	            resolve();
324	        });
325	    }
326	
327	    /**
328	     * @ch 處理 GAME_INTRO_COMPLETE 事件
329	     * 遊戲介紹完成後顯示 1 個懸賞令（M1、倍率 9999）為「已定位」靜止畫面（不播 In 進場）。
330	     * 前提：呼叫時場上保證為空（開場第一次顯示），故直接設定 item[0]、不需清場。
331	     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支。
332	     */
333	    private HandleGameIntroComplete() {
334	        this.EnsureCurrentBountySize();
335	        this.NormalizeGhosts();   // 防禦：0→1 前確保無殘留 ghost（正常此路徑場上為空）
336	        const item = this.m_wantedPosterItems[0];
337	        if (!item) {
338	            warn('[WantedPosterManager] GAME_INTRO_COMPLETE: 懸賞令物品[0] 未設置');
339	            return;
340	        }
341	        const data: IBountyData = { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 9999, MultipleIndex: 0 };
342	        // 先 active 再 setSkin：inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
343	        item.node.active = true;
344	        item.SetWantedPosterData(data);
345	        item.ShowInSettled();           // 直接顯示 In 定位完成的靜止畫面（不播進場）
346	        this.m_currentBounty[0] = data;
347	    }
348	    //#endregion Event Management
349	
350	    //#region Methods
351	    /**
352	     * @ch 設置懸賞令資料（以 BaseSymbol multiset 比對前後狀態 — 決定 進場 / 退場 / 退場再進場 / 持續）
353	     *
354	     * 比對規則（內容式，計數 multiset；每個 BaseSymbol 綁定一個 item，持續者保留原綁定）：
355	     * - BC-20 isNewRound=true（新一局）→ 現有全部退場、新清單全部進場（整批重建）
356	     * - BC-21 同局・新增 BaseSymbol（計數增加）→ 進場（SetData + active + PlayIn）
357	     * - BC-22 同局・移除 BaseSymbol（計數減少）→ 退場（PlayOut → active=false）
358	     * - BC-23 同局・同 BaseSymbol・Multiple 變 → 原 item 退場再進場（PlayOut → SetData → PlayIn）
359	     * - BC-24 同局・同 BaseSymbol・Multiple 同・盤面(扣除被消除位置)已無此符號 → 原 item 退場再進場
360	     * - BC-25 同局・同 BaseSymbol・Multiple 同・盤面仍可見 → 持續，不播動畫
361	     * 位置重排一律交由 cc.Layout（本元件只處理 In/Out 動畫，不碰節點位置）。
362	     *
363	     * @param dataList 本輪懸賞令資料（Multiple>0 才顯示）
364	     * @param isNewRound 是否新一局（強制整批重建）；省略視為同局 cascade
365	     * @param visibleBaseSymbols 盤面(扣除被消除位置)目前可見的 BaseSymbol；僅 cascade 需傳，省略視為全可見
366	     */
367	    private SetWantedPosterData(dataList: IBountyData[], isNewRound: boolean = false, visibleBaseSymbols?: number[]) {
368	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
369	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
370	            return;
371	        }
372	        this.EnsureCurrentBountySize();
373	
374	        const count = this.m_wantedPosterItems.length;
375	        // 本輪要顯示的 bounty（Multiple>0 且 BaseSymbol 非 Wanted_Empty 佔位），超量截斷至 item 數量上限
376	        // BaseSymbol === Wanted_Empty 視同空資料（懸賞海報空位），一併排除不顯示
377	        const newBounties = dataList.filter(d => d && d.Multiple > 0 && d.BaseSymbol !== Symbol.Wanted_Empty);
378	        if (newBounties.length > count) {
379	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
380	                newBounties.length, '>', count);
381	            newBounties.length = count;
382	        }
383	
384	        if (isNewRound) {
385	            this.RebuildAll(newBounties);
386	        } else {
387	            this.ReconcileCascade(newBounties, visibleBaseSymbols);
388	        }
389	    }
390	
391	    /**
392	     * @ch BC-20 整批重建（新一局）：現有全部 Out 並關閉，全部 Out 完成後新清單依序設資料、active、PlayIn。
393	     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
394	     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
395	     */
396	    private RebuildAll(newBounties: IBountyData[]) {
397	        // 整批重建前先釋放殘留 ghost：使下方以 node.active 判退場的迴圈不被 ghost（active 但隱形）干擾（BC-G4 · D5）
398	        this.NormalizeGhosts();
399	        const count = this.m_wantedPosterItems.length;
400	
401	        const outPromises: Promise<void>[] = [];
402	        for (let i = 0; i < count; i++) {
403	            const item = this.m_wantedPosterItems[i];
404	            if (item && item.node.active) {
405	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
406	            }
407	            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
408	            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
409	        }
410	
411	        const enterAll = () => {
412	            for (let i = 0; i < newBounties.length; i++) {
413	                const item = this.m_wantedPosterItems[i];
414	                if (!item) continue;
415	                // 先 active 再 ShowContent 再 setSkin：inactive/Content off 時 setSkin 不重建 render data（殘留舊 skin）
416	                item.node.active = true;
417	                item.SetContentVisible(true);
418	                item.SetWantedPosterData(newBounties[i]);
419	                item.PlayIn();
420	            }
421	        };
422	
423	        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
424	        else enterAll();
425	    }
426	
427	    /**
428	     * @ch 同局 cascade 對帳：以 BaseSymbol multiset 比對目前綁定 ↔ 新清單，保留持續者的 item 綁定。
429	     *     - 同 BaseSymbol・Multiple 同・盤面仍可見 → 持續（不動）         [BC-25]
430	     *     - 同 BaseSymbol・Multiple 變 或 盤面已無此符號 → 原 item 退場再進場 [BC-23/BC-24]
431	     *     - 多出的新 BaseSymbol → 進場（優先用原本就空的 item；不足才等退場者騰出版位）[BC-21]
432	     *     - 少掉的舊 BaseSymbol → 退場                                  [BC-22]
433	     * @param visibleBaseSymbols 盤面(扣除被消除位置)可見的 BaseSymbol；省略視為全可見
434	     */
435	    private ReconcileCascade(newBounties: IBountyData[], visibleBaseSymbols?: number[]) {
436	        const count = this.m_wantedPosterItems.length;
437	        const visible = visibleBaseSymbols ? new Set(visibleBaseSymbols) : null;
438	
439	        // 新清單依 BaseSymbol 分組成可消耗的 pool（multiset）
440	        const pool = new Map<number, IBountyData[]>();
441	        for (const b of newBounties) {
442	            const list = pool.get(b.BaseSymbol);
443	            if (list) list.push(b); else pool.set(b.BaseSymbol, [b]);
444	        }
445	
446	        const preFreeSlots: number[] = [];      // 更新前就空著的 item（含 pre-existing ghost），供進場立即 reuse
447	        const vacatingSlots: number[] = [];     // 本輪「真消失」騰出的 item，Out 完才可用
448	        const outPromises: Promise<void>[] = [];
449	        const deferredEnter: IBountyData[] = [];
450	        const leavingSlots: number[] = [];      // BC-22 離場者：ghost vs 真消失待 Pass A 後依 hasSurvivor 決定
451	        let hasSurvivor = false;                // 任一 BC-25 持續者（全程沒播 Out/In）→ 需 ghost 撐位防 snap
452	
453	        // Pass A：逐一決定目前已綁定 item 的命運（BC-22 離場決策延後到收尾）
454	        for (let i = 0; i < count; i++) {
455	            const cur = this.m_currentBounty[i];
456	            const item = this.m_wantedPosterItems[i];
457	            if (cur === null) {
458	                if (item) preFreeSlots.push(i);              // 空格或 pre-existing ghost（皆可被新進場 reuse）
459	                continue;
460	            }
461	            const bs = cur.BaseSymbol;
462	            const list = pool.get(bs);
463	            if (list && list.length > 0) {
464	                const onBoard = visible ? visible.has(bs) : true;
465	                // 優先配對「相同 Multiple」以持續（不播動畫）；盤面不可見則一律退場再進場
466	                const sameIdx = onBoard ? list.findIndex(b => b.Multiple === cur.Multiple) : -1;
467	                if (sameIdx >= 0) {
468	                    list.splice(sameIdx, 1);                 // BC-25 持續：消耗一筆，item 不動
469	                    hasSurvivor = true;                      // 連續顯示者，被搬動會被察覺 → 需 ghost 撐位
470	                } else {
471	                    const nb = list.shift()!;                // BC-23/BC-24 退場再進場（有 In 動畫遮蓋，不算 survivor）
472	                    if (item) item.PlayOut().then(() => { item.SetWantedPosterData(nb); item.PlayIn(); });
473	                    this.m_currentBounty[i] = nb;
474	                }
475	                if (list.length === 0) pool.delete(bs);
476	            } else {
477	                leavingSlots.push(i);                        // BC-22 離場：ghost/gone 待收尾決策
478	            }
479	        }
480	
481	        // Pass A 收尾：依 hasSurvivor 對離場者統一決策（ghost 撐位 vs 真消失）
482	        for (const i of leavingSlots) {
483	            const item = this.m_wantedPosterItems[i];
484	            this.m_currentBounty[i] = null;
485	            if (hasSurvivor) {
486	                // BC-G1 轉 ghost：item root 維持 active 撐住 Layout 版位，讓 BC-25 持續者不 snap
487	                if (item) {
488	                    item.ClearBaseSymbol();
489	                    outPromises.push(item.PlayOut().then(() => { item.SetContentVisible(false); }));
490	                }
491	            } else {
492	                // 真消失：無連續 survivor 需保護
493	                if (item) outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
494	                vacatingSlots.push(i);
495	            }
496	        }
497	
498	        // Pass B：pool 剩餘 = 需進場的新 BaseSymbol [BC-21]
499	        const remaining: IBountyData[] = [];
500	        for (const list of pool.values()) remaining.push(...list);
501	        for (const nb of remaining) {
502	            if (preFreeSlots.length > 0) {
503	                this.EnterAt(preFreeSlots.shift()!, nb);     // 有現成空位/pre-existing ghost → 立即 reuse 進場
504	            } else {
505	                deferredEnter.push(nb);                      // 無現成空位 → 等退場者騰出
506	            }
507	        }
508	
509	        // 收尾：deferredEnter 等退場騰位 + postReal===0 釋放殘留 ghost（§5.3.1）
510	        // NormalizeGhosts 只釋放「active 且綁定 null」者；先 enter 後 normalize，EnterAt 已填綁定的格不受影響
511	        const needReleaseLingering = !this.m_currentBounty.some(b => b !== null);
512	        if (deferredEnter.length > 0 || needReleaseLingering) {
513	            Promise.all(outPromises).then(() => {
514	                for (const nb of deferredEnter) {
515	                    const idx = vacatingSlots.shift();
516	                    if (idx === undefined) break;            // 理論上不會（已截斷至 count）
517	                    this.EnterAt(idx, nb);
518	                }
519	                if (needReleaseLingering) this.NormalizeGhosts();
520	            });
521	        }
522	    }
523	
524	    /**@ch 在指定 item 版位進場：設資料、active、PlayIn 並記錄綁定*/
525	    private EnterAt(index: number, data: IBountyData) {
526	        const item = this.m_wantedPosterItems[index];
527	        if (!item) return;
528	        // 先 active 再 ShowContent 再 setSkin：reuse ghost 格時 Content 仍 off，須先開可見，
529	        // 否則 inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
530	        item.node.active = true;
531	        item.SetContentVisible(true);
532	        item.SetWantedPosterData(data);
533	        item.PlayIn();
534	        this.m_currentBounty[index] = data;
535	    }
536	
537	    /**
538	     * @ch 釋放所有 ghost（node.active 但綁定為 null）→ 還原為真消失 + Content 預設可見。
539	     * 用於：RebuildAll / HandleGameIntroComplete 起手（整批前清殘留，使 node.active 判定不被 ghost 干擾）、
540	     *       ReconcileCascade / HandlePlayMarkActive 退到全空時（避免上一輪保留的 ghost 隱形殘留 · BC-G4）。
541	     */
542	    private NormalizeGhosts() {
543	        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
544	            const item = this.m_wantedPosterItems[i];
545	            if (item && item.node.active && this.m_currentBounty[i] === null) {
546	                item.node.active = false;
547	                item.SetContentVisible(true);   // 還原 Content 預設態，供下次進場
548	                item.ClearBaseSymbol();
549	            }
550	        }
551	    }
552	
553	    /**@ch 確保綁定追蹤陣列長度與 item 數一致（初次/變動時補 null、保留既有）*/
554	    private EnsureCurrentBountySize() {
555	        const count = this.m_wantedPosterItems.length;
556	        if (this.m_currentBounty.length === count) return;
557	        const next: (IBountyData | null)[] = new Array(count).fill(null);
558	        const keep = Math.min(this.m_currentBounty.length, count);
559	        for (let i = 0; i < keep; i++) next[i] = this.m_currentBounty[i];
560	        this.m_currentBounty = next;
561	    }
562	
563	    /**
564	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
565	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
566	     */
567	    private GetItemsByBaseSymbol(baseSymbol: number): WantedPosterItem[] {
568	        if (baseSymbol === null || baseSymbol === undefined) return [];
569	        const result: WantedPosterItem[] = [];
570	        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
571	            const item = this.m_wantedPosterItems[i];
572	            const cur = this.m_currentBounty[i];
573	            // 用 m_currentBounty 判斷「正在顯示真懸賞令」，排除 ghost（node.active 但綁定為 null）
574	            // — ghost 的 GetBaseSymbol() 已 ClearBaseSymbol 為 MAX，但以綁定為準更直接（BC-G5）
575	            if (item && item.node.active && cur !== null && cur.BaseSymbol === baseSymbol) {
576	                result.push(item);
577	            }
578	        }
579	        return result;
580	    }
581	    /**
582	     * @ch 設置懸賞令 UI 顯示狀態
583	     * @param isShow 是否顯示
584	     */
585	    private SetWantedPosterUIShow(isShow: boolean) {
586	        if (!this.m_rootNode) {
587	            warn('[WantedPosterManager] SetWantedPosterUIShow: 根節點未設置');
588	            return;
589	        }
590	        this.m_rootNode.active = isShow;
591	    }
592	    //#endregion Methods
593	
594	    //#region 測試功能
595	    /**
596	     * @ch 測試按鍵處理
597	     * - 數字鍵 1：顯示 1 個懸賞令
598	     * - 數字鍵 2：顯示 2 個懸賞令
599	     * - 數字鍵 3：顯示 UI
600	     * - 數字鍵 4：隱藏 UI
601	     */
602	    private CheckTestKeyCode(event: EventKeyboard): void {
603	        if (!DEBUG) return;
604	        switch (event.keyCode) {
605	            case KeyCode.DIGIT_1:
606	                // 測試：顯示 1 個懸賞令
607	                this.SetWantedPosterData([
608	                    { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 2, MultipleIndex: 0 },
609	                ], true);
610	                break;
611	
612	            case KeyCode.DIGIT_2:
613	                // 測試：顯示 2 個懸賞令
614	                this.SetWantedPosterData([
615	                    { BaseSymbol: Symbol.M4, BountySymbol: 0, Multiple: 256, MultipleIndex: 0 },
616	                    { BaseSymbol: Symbol.M8, BountySymbol: 0, Multiple: 9999, MultipleIndex: 1 },
617	                ], true);
618	                break;
619	
620	            case KeyCode.DIGIT_3:
621	                // 測試：顯示 UI
622	                this.SetWantedPosterUIShow(true);
623	                break;
624	
625	            case KeyCode.DIGIT_4:
626	                // 測試：隱藏 UI
627	                this.SetWantedPosterUIShow(false);
628	                break;
629	        }
630	    }
631	    //#endregion 測試功能
632	}
633	
