                    await spine.PlayAnimation(
                        introAnimationKey,
                        spine.Spine,
                        false,
                        undefined,
                        ( eventName ) => this.OnIntroSpineEvent( eventName )
                    );
                    resolve();
                }
            }));    
        }

        await Promise.all(promises);

        for (let i = index*this.m_spines.length/2; i < (index+1)*this.m_spines.length/2; i++) 
        {
            this.m_spines[ i ].SetSpineNodeActivity(false);
        }

        Common.SetLockOrientation(false);
        this.unschedule(this.PlayIntroBgm);
        cb?.();
        this.SetBlackMaskShow(true);
        this.node.active = false;
    }

    /**
